// ── Percussion v2 UI (owner 2026-07-10) ─────────────────────
// A user-editable layer list replaces the fixed Beat/Motif/Downbeat trio.
// Percussion can be switched off (greyed out) and is off by default on fresh
// patches (see resolvePercEnabled). Each layer picks a role (its trigger), a
// sound (a built-in sample OR a single-attack render of a sub-note instrument,
// chosen from a searchable smart dropdown), a level, and — in the sub-note
// SPACE panel — its own position.
const PERC_ROLES = [["beat", "Beat"], ["motif", "Motif"], ["downbeat", "Downbeat"]];
function percLayerHue(i) { return (32 + i * 47) % 360; }

// value strings for the sound smart-combo: "sample:<key>" | "inst:<presetId>"
function percSoundValue(sound) {
  if (sound && sound.kind === "instrument") return `inst:${sound.presetId ?? sound.name ?? ""}`;
  return `sample:${(sound && sound.key) || "click"}`;
}
function percSoundLabel(sound) {
  if (sound && sound.kind === "instrument") return sound.name || "Instrument";
  const key = (sound && sound.key) || "click";
  return (PERC_SOUNDS[key] && PERC_SOUNDS[key].label) || key;
}
// Single-layer sub-note patches offered as percussion instruments: any preset
// carrying a sound half and NOT stacking extra layers.
function percInstrumentOptions() {
  const seen = new Set();
  const opts = [];
  for (const preset of [...FACTORY_PRESETS, ...loadPresets()]) {
    const params = preset && preset.parameters;
    if (!params) continue;
    if (Array.isArray(params.layers) && params.layers.length) continue; // single-layer only
    const id = String(preset.id);
    if (!id || seen.has(id)) continue;
    seen.add(id);
    opts.push({ value: `inst:${id}`, label: preset.name || id, note: preset.family || preset.section || "instrument" });
  }
  return opts;
}
// value → a sound descriptor, snapshotting the instrument's sound half.
function percResolveSound(value) {
  const idx = String(value).indexOf(":");
  const kind = idx < 0 ? "sample" : String(value).slice(0, idx);
  const key = idx < 0 ? String(value) : String(value).slice(idx + 1);
  if (kind !== "inst") return { kind: "sample", key: key || "click" };
  const preset = [...FACTORY_PRESETS, ...loadPresets()].find(x => String(x.id) === key);
  if (!preset || !preset.parameters) return { kind: "sample", key: "click" };
  const subnote = extractSectionParams(migrateToneParams({ ...preset.parameters }), "sound");
  for (const k of Object.keys(subnote)) if (k.startsWith("layer") || k.startsWith("baseLayer")) delete subnote[k]; // never nest layer-stack controls
  return { kind: "instrument", name: preset.name || key, presetId: key, pitchHz: 220, subnote };
}
function percSoundComboHTML(l) {
  const groups = [
    { label: "Samples", options: Object.entries(PERC_SOUNDS).map(([k, s]) => ({ value: `sample:${k}`, label: s.label, note: "sample" })) },
    { label: "Sub-note instruments", options: percInstrumentOptions() },
  ];
  return smartComboHTML({
    id: `percSnd-${l.id}`,
    value: percSoundValue(l.sound),
    buttonLabel: percSoundLabel(l.sound),
    placeholder: "Search sounds…",
    groups,
  });
}
function percLayerRowHTML(l, i) {
  const roleOpts = PERC_ROLES.map(([v, label]) =>
    `<option value="${v}"${l.role === v ? " selected" : ""}>${label}</option>`).join("");
  const isInst = !!(l.sound && l.sound.kind === "instrument");
  return `
    <div class="perc-lyr" data-perc-layer="${l.id}" style="--layer-hue:${percLayerHue(i)}">
      <div class="perc-lyr-head">
        <select class="perc-lyr-role" data-perc-role="${l.id}" title="When this layer fires">${roleOpts}</select>
        <button type="button" class="pal-btn perc-lyr-remove" data-perc-remove="${l.id}" title="Remove this layer">×</button>
      </div>
      <div class="perc-lyr-sound">${percSoundComboHTML(l)}</div>
      <div class="perc-lyr-ctls">
        <canvas class="layer-minipad compact-space-target" data-perc-pad="${l.id}" width="40" height="40"
          title="Where this hit sits in the room — drag ↔ for angle, ↕ for distance (the Space stage shows it, this is where it's set)"></canvas>
        <label class="sp-ctl">Vol <input type="range" data-perc-vol="${l.id}" min="0" max="1" step="0.01" value="${l.vol ?? 0}"/></label>
        ${l.role === "downbeat" ? `<label class="sp-ctl">Every <input type="range" data-perc-every="${l.id}" min="1" max="16" step="1" value="${l.every ?? 4}"/></label>` : ""}
        ${isInst ? `<label class="sp-ctl" title="Fixed pitch of the instrument hit (does not track the key)">Pitch <input type="range" data-perc-pitch="${l.id}" min="60" max="880" step="1" value="${l.sound.pitchHz ?? 220}"/></label>` : ""}
      </div>
    </div>`;
}
function productionPanelHTML(p) {
  // Owner-clarified model: reverb/space TYPE lives with the global space
  // (producer, Q6); each patch keeps its own space in the SPACE stage. The
  // reverb params stay in the params object. Percussion is a switchable,
  // user-editable layer list (percLayers); off by default on fresh patches.
  const enabled = resolvePercEnabled(p);
  const layers = ensurePercLayers(p);
  const rows = layers.map((l, i) => percLayerRowHTML(l, i)).join("");
  return `
    <div class="perf-panel production-panel">
      <div class="perf-section percussion-section">
        <div class="perc-enable-row">
          <label class="perc-enable-toggle" title="Turn percussion on or off for this patch">
            <input type="checkbox" data-perc-enable ${enabled ? "checked" : ""}/>
            <span>Percussion</span>
          </label>
          <span class="perc-enable-hint">${enabled ? "Accents layer over the motif — sound, level & position are per layer." : "Off — enable to add rhythmic accents."}</span>
        </div>
        <div class="perc-body${enabled ? "" : " perc-disabled"}" data-perc-body${enabled ? "" : ' aria-disabled="true"'}>
          ${panelPresetBarHTML("percussion")}
          <div class="perc-list" data-perc-list>${rows || `<div class="perc-empty">No layers yet — add one below.</div>`}</div>
          <button type="button" class="perc-add" data-perc-add>＋ Add layer</button>
        </div>
      </div>
    </div>`;
}

// Re-render just the percussion production panel in place (add/remove/role/kind
// changes restructure it) and re-wire, so the rest of the view is untouched.
function rerenderProductionPanel(v) {
  const old = v.querySelector(".production-panel");
  if (!old) return;
  const tmp = document.createElement("div");
  tmp.innerHTML = productionPanelHTML(exploreParams);
  const fresh = tmp.firstElementChild;
  if (!fresh) return;
  old.replaceWith(fresh);
  wirePercussionPanel(v);
  wirePanelPresetBars(v);
}

// Live-apply percussion edits to a running performance (no restart). When
// stopped this is a no-op — the next play() reads exploreParams directly.
function applyPerc() {
  if (synth.isPlaying) synth.updatePercLayers({ ...exploreParams });
}

function wirePercussionPanel(v) {
  const percLayers = () => Array.isArray(exploreParams.percLayers)
    ? exploreParams.percLayers
    : (exploreParams.percLayers = ensurePercLayers(exploreParams));
  const byId = (id) => (exploreParams.percLayers || []).find(l => l.id === id);

  // Per-drum-track position (owner 2026-07-15): each hit is placed HERE, with
  // the same compact target pad the producer's track heads use. The Space
  // stage only shows (and can highlight) the result.
  v.querySelectorAll("[data-perc-pad]").forEach(cv => {
    const id = cv.dataset.percPad;
    wireCompactSpaceTarget(cv, {
      get: () => {
        const l = byId(id);
        return {
          angle: l?.space?.angle ?? percGroupAngle(exploreParams),
          dist: l?.space?.dist ?? (Number.isFinite(exploreParams.percDistance)
            ? exploreParams.percDistance : (exploreParams.spaceDistance ?? 2.5)),
        };
      },
      hue: () => percLayerHue((exploreParams.percLayers || []).findIndex(l => l.id === id)),
      set: (pos) => {
        const l = byId(id);
        if (!l) return;
        l.space = { angle: Math.round(pos.angle), dist: pos.dist };
        applyPerc();
        drawStageBig(); // live echo on the Space stage if it's on screen
      },
    });
  });

  const enableEl = v.querySelector("[data-perc-enable]");
  if (enableEl) enableEl.onchange = () => {
    exploreParams.percEnabled = enableEl.checked;
    if (enableEl.checked) percLayers(); // materialise the list so it round-trips
    rerenderProductionPanel(v);
    applyPerc();
  };

  const list = v.querySelector("[data-perc-list]");
  if (!list) return;

  v.querySelectorAll("[data-perc-role]").forEach(sel => {
    sel.onchange = () => {
      const l = byId(sel.dataset.percRole);
      if (!l) return;
      l.role = sel.value;
      if (l.role === "downbeat" && l.every == null) l.every = 4;
      rerenderProductionPanel(v); // Every control appears/disappears with the role
      applyPerc();
    };
  });
  v.querySelectorAll("[data-perc-vol]").forEach(sl => {
    sl.oninput = () => { const l = byId(sl.dataset.percVol); if (l) { l.vol = parseFloat(sl.value); applyPerc(); } };
  });
  v.querySelectorAll("[data-perc-every]").forEach(sl => {
    sl.oninput = () => { const l = byId(sl.dataset.percEvery); if (l) { l.every = parseInt(sl.value, 10) || 4; applyPerc(); } };
  });
  v.querySelectorAll("[data-perc-pitch]").forEach(sl => {
    sl.oninput = () => {
      const l = byId(sl.dataset.percPitch);
      if (l && l.sound && l.sound.kind === "instrument") { l.sound.pitchHz = parseFloat(sl.value); applyPerc(); }
    };
  });
  v.querySelectorAll("[data-perc-remove]").forEach(btn => {
    btn.onclick = () => {
      exploreParams.percLayers = (exploreParams.percLayers || []).filter(l => l.id !== btn.dataset.percRemove);
      rerenderProductionPanel(v);
      applyPerc();
    };
  });
  const addBtn = v.querySelector("[data-perc-add]");
  if (addBtn) addBtn.onclick = () => {
    percLayers().push({ id: percLayerId(), role: "beat", vol: 0.35, sound: { kind: "sample", key: "click" }, space: null });
    rerenderProductionPanel(v);
    applyPerc();
  };

  // Sound pickers (searchable). Changing sound KIND toggles the pitch control,
  // so re-render on an instrument↔sample switch; otherwise just apply live.
  wireSmartCombos(list, (combo, value) => {
    const id = combo.id.replace("percSnd-", "");
    const l = byId(id);
    if (!l) return;
    const wasInst = !!(l.sound && l.sound.kind === "instrument");
    l.sound = percResolveSound(value);
    if ((l.sound.kind === "instrument") !== wasInst) rerenderProductionPanel(v);
    applyPerc();
  });
}

// ── Q7: layered subnote modules ─────────────────────────────
// Coloured blocks along the bottom of the sub-note view: ＋ captures the
// CURRENT subnote half as a new layer; each block gets level, position and
// an independent-head toggle; the strip header can sync envelope draws.
let _chLayerSel = null; // selected layer id (opens its mini panel)

// One layer's envelope-baseline line. While synchronised, the chance and
// the ± magnitudes come from the shared panel (identical on every row);
// the means stay the layer's own.
function layerEnvLineText(l, p) {
  const sn = l.sound || l.subnote || {};
  const syncActive = !!p.layerEnvOverride;
  const prof = SPECTRAL_PROFILES[sn.spectralProfile]?.label || sn.spectralProfile || "custom";
  const v = (k, fb) => sn[k] ?? p[k] ?? fb;
  const ms = (x) => Math.round(x * 1000);
  const prob = syncActive ? (p.layerEnvProb ?? 0.5) : v("envelopeProb", 0);
  const sd = (ownKey, sharedKey, fb) => syncActive ? (p[sharedKey] ?? fb) : v(ownKey, fb);
  return [
    prof,
    `var ${Math.round(prob * 100)}%${syncActive ? " (synced)" : ""}`,
    `A ${ms(v("envelopeAttack", 0.008))}±${ms(sd("envelopeAttackSd", "layerEnvAttackSd", 0.006))}ms`,
    `D ${ms(v("envelopeDecay", 0.04))}±${ms(sd("envelopeDecaySd", "layerEnvDecaySd", 0.018))}ms`,
    `S ${Math.round(v("envelopeSustain", 0.6) * 100)}±${Math.round(sd("envelopeSustainSd", "layerEnvSustainSd", 0.08) * 100)}%`,
    `R ${ms(v("envelopeRelease", 0.08))}±${ms(sd("envelopeReleaseSd", "layerEnvReleaseSd", 0.035))}ms`,
  ].join(" · ");
}

// Refresh every row's baseline line in place (no re-render — the shared
// SD sliders live-update mid-drag).
function refreshLayerEnvLines() {
  (exploreParams.layers || []).forEach(l => {
    const row = document.querySelector(`[data-layer-row="${l.id}"] .layer-env`);
    if (row) row.textContent = layerEnvLineText(l, exploreParams);
  });
}

// A layer's EFFECTS stack, shown on its row as toggleable tags with a wet
// mini-slider — the same chain edited in full on the EFFECTS stage when this
// layer is loaded into the editor (docs/EFFECTS_CONTRACT.md).
// Effect tags for a layer row (or the base row, ownerId "base"). The
// data-layer-fx-* keys encode `${ownerId}::${uid}`; the bind resolves "base"
// to the patch's own chain (docs/EFFECTS_CONTRACT.md).
function fxTagsHTML(ownerId, chainSpec, stageOff) {
  const chain = sanitizeFxChain(chainSpec);
  if (!chain.length) return "";
  return `<div class="layer-fx${stageOff ? " off" : ""}" title="Effects on this ${ownerId === "base" ? "base sound" : "layer"} — click a tag to bypass it, drag its bar for wet/dry. Select the ${ownerId === "base" ? "base" : "layer"} to edit the full rack on the EFFECTS stage.">
    ${chain.map(fx => {
      const mod = effectModuleById(fx.type);
      const enabled = fx.enabled !== false;
      return `<span class="layer-fx-tag${enabled ? "" : " off"}" style="--wet:${Math.round((fx.wet ?? 1) * 100)}%">
        <button class="layer-fx-name" data-layer-fx-toggle="${ownerId}::${fx.uid}" title="Double-click to ${enabled ? "bypass" : "enable"} ${esc(mod ? mod.name : fx.type)}">${esc(mod ? mod.name : fx.type)}</button>
        <label class="layer-fx-mix"><span>dry</span><input type="range" class="layer-fx-wet" data-layer-fx-wet="${ownerId}::${fx.uid}" min="0" max="1" step="0.01" value="${fx.wet ?? 1}" title="Wet / dry"/><span>wet</span></label>
      </span>`;
    }).join("")}
  </div>`;
}
function layerFxTagsHTML(l) {
  const sound = l.sound || l.subnote || {};
  return fxTagsHTML(l.id, sound.effectsChain, sound.stageEffectsOn === false);
}

// A layer's display title — its own name if set (double-click to rename), else
// the positional default "Layer N" (base is layer 1, so extras start at 2).
function layerTitle(l, i) {
  return (l.name && String(l.name).trim()) || `Layer ${i + 1}`;
}

function layerStripHTML(p, compact = false) {
  const layers = Array.isArray(p.layers) ? p.layers : [];
  const selectedId = p.selectedLayerId || layers[0]?.id;
  if (compact) {
    return `
    <div class="layer-strip" id="layerStrip">
      <span class="layer-strip-label" title="${esc(PARAM_DESC.layers)}">LAYERS</span>
      <button class="layer-add" id="layerAdd" title="Clone the selected sound as a new layer">＋</button>
      <span class="layer-strip-note">${layers.length} layer${layers.length === 1 ? "" : "s"} on the stage above</span>
    </div>`;
  }
  const rows = layers.map((layer, index) => {
    const sound = layer.sound || layer.subnote || {};
    const envStr = layerEnvLineText({ ...layer, subnote: sound }, p);
    const title = (layer.name && String(layer.name).trim()) || (index === 0 ? "Untitled" : `Layer ${index + 1}`);
    return `
    <div class="layer-row${index === 0 ? " base-row" : ""}${layer.id === selectedId ? " sel" : ""}" data-layer-row="${layer.id}" style="--layer-hue:${layer.hue ?? (36 + index * 70) % 360}" title="Layer ${index + 1} — click to edit it in the stages above">
      <span class="layer-row-tag">${index + 1}</span>
      <span class="space-target-control layer-space-target">
        <canvas class="layer-minipad compact-space-target" data-layer-pad="${layer.id}" width="40" height="40"></canvas>
        <span data-space-target-readout>${compactSpaceTargetText({ angle: layer.space?.angle ?? 0, dist: layer.space?.dist ?? 2.5 })}</span>
      </span>
      <div class="layer-row-lines">
        <div class="layer-name-row">
          <span class="layer-name" data-layer-name="${layer.id}" title="Double-click to rename this layer">${esc(title)}</span>
          ${index === 0 ? '<span class="layer-base-badge">BASE</span>' : ""}
        </div>
        <div class="layer-row-space">
          <label class="sp-ctl">Vol <input type="range" data-layer-gain="${layer.id}" min="0" max="1.5" step="0.01" value="${layer.gain ?? 1}" title="This layer's level"/></label>
          <button class="pal-btn layer-solo${layer.solo ? " on" : ""}" data-layer-solo="${layer.id}" title="Solo this layer">S</button>
          ${index === 0 ? "" : `<button class="pal-btn" data-layer-recapture="${layer.id}" title="Copy the selected layer's sound into this layer">⟳</button>
          <button class="pal-btn" data-layer-remove="${layer.id}" title="Remove this layer">×</button>`}
        </div>
        <div class="layer-env" title="This layer's envelope baseline">${esc(envStr)}</div>
        ${fxTagsHTML(layer.id, sound.effectsChain, sound.stageEffectsOn === false)}
      </div>
    </div>`;
  }).join("");
  const syncOn = !!p.layerEnvOverride;
  return `
    <div class="layer-strip" id="layerStrip">
      <span class="layer-strip-label" title="${esc(PARAM_DESC.layers)}">LAYERS</span>
      <button class="layer-add" id="layerAdd" title="Clone the selected sound as another layer">＋</button>
    </div>
    <div class="layer-area">
      <div class="layer-rows">${rows}</div>
      ${layers.length > 1 ? `
      <div class="layer-sync">
        <div class="subsection-label">Synchronised variation</div>
        <label class="layer-env-sync" title="${esc(PARAM_DESC.layerEnvOverride)}">
          <input type="checkbox" id="layerEnvSync"${syncOn ? " checked" : ""}/> variations fire together
        </label>
        <div class="layer-sync-body${syncOn ? "" : " off"}">
          ${controlRow("layerEnvProb", "Chance", p.layerEnvProb ?? 0.5, 0, 1, 0.01)}
          ${controlRow("layerEnvAttackSd", "Attack SD", p.layerEnvAttackSd ?? 0.015, 0, 0.12, 0.001)}
          ${controlRow("layerEnvDecaySd", "Decay SD", p.layerEnvDecaySd ?? 0.04, 0, 0.25, 0.001)}
          ${controlRow("layerEnvSustainSd", "Sustain SD", p.layerEnvSustainSd ?? 0.08, 0, 0.45, 0.01)}
          ${controlRow("layerEnvReleaseSd", "Release SD", p.layerEnvReleaseSd ?? 0.05, 0, 0.3, 0.001)}
        </div>
      </div>` : ""}
    </div>`;
}

// The tiny head-relation diagram on each layer row.
function drawLayerMiniPads() {
  const pads = exploreParams.layers || [];
  pads.forEach(l => {
    const cv = document.querySelector(`[data-layer-pad="${l.id}"]`);
    if (!cv) return;
    const angle = l.space?.angle ?? 0;
    const dist = l.space?.dist ?? 2.5;
    drawCompactSpaceTarget(cv, { angle, dist }, l.hue ?? 36, !!l.mute);
  });
}

function subnotePresetLabel(p = exploreParams) {
  const custom = String(p.spectralProfileName || "").trim();
  if (custom) return custom;
  return (SPECTRAL_PROFILES[p.spectralProfile] || SPECTRAL_PROFILES.violin).label;
}

function subnoteWorkspaceHTML(p) {
  const formantMode = isFormantMode(p);
  const fourierDisabled = formantMode ? " mode-disabled" : "";
  const formantDisabled = formantMode ? "" : " mode-disabled";
  const title = subnotePresetLabel(p);
  return `
    <div class="card subnote-full-card ${formantMode ? "is-formant-mode" : "is-fourier-mode"}">
      <div class="subnote-full-layout">
        ${formantMode ? `
          <div class="formant-stage" data-sound-path="formant" aria-disabled="false">
            <div class="subnote-head">
              <div>
                <div class="section-label">Formant Accuracy</div>
                <h2>All formants</h2>
              </div>
              <div class="signature-legend">
                <span><i class="legend-line acc"></i> accuracy</span>
                <span><i class="legend-line surp"></i> surprise</span>
              </div>
            </div>
            ${formantAccuracyControlsHTML(p)}
            <canvas class="formant-canvas accuracy-canvas" id="cvFormantAccuracy" width="760" height="360"></canvas>
          </div>
        ` : `
          <div class="harmonic-stage chorda" data-sound-path="fourier" aria-disabled="false">
            <!-- CHORDA (owner-chosen direction 2026-07-07): one truth-canvas,
                 four annotators. The chain is a rail of thumbnail cards; the
                 selected stage expands into the inspector; the partial field
                 is the shared display everything indexes into. -->
            <div class="ch-head">
              <div class="ch-title-block">
                <h2 class="ch-preset-title" id="chPresetTitle" title="Double-click to rename this sound">${esc(title)}</h2>
                <span class="layer-edit-tag" title="The stages above edit the selected layer">editing Layer ${Math.max(1, (p.layers || []).findIndex(l => l.id === p.selectedLayerId) + 1)}</span>
              </div>
              <!-- Owner 07-08: no preset dropdown or mix slider here — the
                   instrument cards below are the one place a recipe is
                   chosen, and spectralMix is a legacy blend (in the fourier
                   voice it is only a flat gain on the tone print), so it
                   rides along in presets without a control. -->
              <div class="ch-readout">f₀ <b>${(p.tonicHz || 261.63).toFixed(1)} Hz</b> · ${esc(noteNameForHz(p.tonicHz || 261.63))} · ${Math.round(p.spectralPartials || 20)} partials</div>
            </div>
            <div class="ch-rail" id="chRail">
              ${chRailCardHTML(p, "excitor", "01", "EXCITOR")}
              <div class="ch-sep">›</div>
              ${chRailCardHTML(p, "resonator", "02", "RESONATOR")}
              <div class="ch-sep">›</div>
              ${chRailCardHTML(p, "body", "03", "BODY")}
              <div class="ch-sep">›</div>
              ${chRailCardHTML(p, "effects", "04", "EFFECTS")}
              <div class="ch-sep">›</div>
              ${chRailCardHTML(p, "space", "05", "SPACE")}
            </div>
            ${_chStage === "effects" ? effectsStageHTML(p) : `
            <div class="ch-main">
              <div class="ch-inspector ch-${_chStage}" id="chInspector" style="--ch-w:${_studioPanels.chW}px">${chInspectorHTML(p)}</div>
              <div class="ch-vsplit" id="chVSplit" title="Drag to resize the inspector"></div>
              <div class="ch-field-wrap">
                <div class="td-field-head">
                  <span class="td-field-title"><span class="td-stage-word ch-${_chStage}-word">${_chStage[0].toUpperCase()}${_chStage.slice(1)}</span> — ${_chStage === "space" ? "Stage" : "Partial Field"}</span>
                </div>
                ${_chStage === "space" ? `
                <!-- V2 spatial stage: the field IS the stage. Sources = base +
                     layers; the only per-layer space property is position. The
                     ear-response (arrival + colouring) now lives in the right
                     column stacked vertically (owner 2026-07-10), so this column
                     is purely the placement view. -->
                <div class="ch-field-pos stage-pos">
                  <canvas id="cvStageBig" title="The stage around your head, seen from above — front is up, the shaded half is behind you. Drag a numbered dot to place that source; rings are metres away. Percussion is placed from the note engine's percussion panel — here it can only be highlighted."></canvas>
                  <label class="sp-showperc" title="Emphasise where the percussion hits sit — position them from the percussion panel on the Macro page">
                    <input type="checkbox" id="spShowPercChk"${_spShowPerc ? " checked" : ""}/> Highlight percussion
                  </label>
                </div>
                ${stageReadoutsHTML(p)}` : `
                <div class="ch-focus-row" id="chFocus">
                  <span class="ch-focus-label">FOCUS</span>
                  ${[["all", "All"], ["odd", "Odd"], ["even", "Even"], ["coupled", "Coupled"], ["longring", "Long ring"], ["wobbly", "Wobbly"]].map(([c, label]) =>
                    `<button class="ch-chip${_chFocus.chip === c ? " active" : ""}" data-ch-chip="${c}">${label}</button>`).join("")}
                  <span class="ch-focus-sum" id="chFocusSum"></span>
                </div>
                <div class="ch-field-pos">
                  <canvas id="cvTonePrint" width="1200" height="330"></canvas>
                  <div class="ch-pin" id="chPin" hidden></div>
                </div>
                <div class="ch-lens-row"><span class="ch-lens-label">LENS</span><canvas id="cvLens" width="1200" height="34"></canvas></div>
                <div class="ch-strip" id="chStrip"></div>`}
              </div>
              ${_chStage === "space" ? `
              <!-- On the SPACE stage the right column carries the EAR RESPONSE
                   (arrival + colouring, stacked vertically) instead of the
                   Envelope/Modulation panel (owner 2026-07-10). -->
              <div class="td-side td-side-ears">
                <div class="ears-head"><span class="ears-head-title">EARS</span><span class="ears-head-sum">what reaches each ear · <b>L</b> blue · <b>R</b> amber</span></div>
                <div class="ears-slot">
                  <canvas id="cvSpaceField" title="WHEN IT ARRIVES: the direct hit then the room's tail. BETWEEN YOUR EARS: the sub-millisecond gap between the ears. HOW IT'S COLOURED: each ear's frequency response from head shadow, pinna, air and proximity."></canvas>
                </div>
              </div>` : `
              <div class="td-side${fourierDisabled}" data-sound-path="fourier" aria-disabled="${formantMode}">
                ${tdSidePanelHTML(p)}
              </div>`}
            </div>
            <div class="ch-status">${_chStage === "space"
              ? `<span>curves follow the pad and knobs live · <b>L</b> ear blue · <b>R</b> ear amber</span><span class="ch-status-right">binaural laws: Woodworth · Brown-Duda · Shaw</span>`
              : `<span><b>drag</b> a stem = level · <b>click</b> = pin readout · <b>brush</b> the lens to focus · knobs drag vertically, double-click resets</span><span class="ch-status-right">display = engine truth · log-f axis</span>`}</div>`}
            <div class="ch-hsplit" id="chHSplit" title="Drag up/down to resize the layers & browser panel"></div>
            <div class="chorda-bottom" id="chordaBottom"${_studioPanels.chordaBottomH ? ` style="height:${_studioPanels.chordaBottomH}px"` : ""}>
              ${layerStripHTML(p) /* V2.2: full rows on every stage — the space rows ARE the source list */}
              ${m2PresetStripHTML(false) /* owner 07-08: ONE browser is the whole selection surface — sound modules + recipes to click or drag onto LAYERS; save lives in the top bar */}
            </div>
          </div>
        `}

      </div>
    </div>
  `;
}

// ── V2 right column: Envelope / Modulation panel ────────────────────
